mapper.select:
SELECT
    COALESCE((
        SELECT COUNT(*)
        FROM repair_requests
        WHERE student_id = #{studentId}
          AND student_name = #{studentName}
    ), 0) AS total_requests,
    COALESCE((
        SELECT COUNT(*)
        FROM repair_requests
        WHERE student_id = #{studentId}
          AND student_name = #{studentName}
          AND status = 'SUBMITTED'
    ), 0) AS pending_review_requests,
    COALESCE((
        SELECT COUNT(*)
        FROM work_orders wo
        INNER JOIN repair_requests rr ON rr.id = wo.repair_request_id
        WHERE rr.student_id = #{studentId}
          AND rr.student_name = #{studentName}
          AND wo.status IN ('ASSIGNED', 'ACCEPTED', 'IN_PROGRESS', 'WAITING_PARTS')
    ), 0) AS active_work_orders,
    COALESCE((
        SELECT COUNT(*)
        FROM repair_requests
        WHERE student_id = #{studentId}
          AND student_name = #{studentName}
          AND status = 'COMPLETED'
          AND DATE_FORMAT(completed_at, '%Y-%m') = DATE_FORMAT(CURRENT_DATE(), '%Y-%m')
    ), 0) AS completed_this_month
FROM dual
